#!/usr/bin/env python3
import argparse
from pathlib import Path

TEMPLATE = """
// AUTO-GENERATED by gen_overload.py

target C {{
  workers: {workers}
}}

preamble {{=
#include <stdlib.h>
#include "core/reactor.h"
#include <inttypes.h>
#include <stdarg.h>
#include <stdio.h>
#include <time.h>
#include <pthread.h>

static int64_t ms_eval_now_mono_ns(void) {{
  struct timespec ts;
  clock_gettime(CLOCK_MONOTONIC, &ts);
  return (int64_t)ts.tv_sec * 1000000000LL + (int64_t)ts.tv_nsec;
}}

static FILE* ms_eval_log_fp = NULL;
static int ms_eval_log_opened = 0;
static pthread_mutex_t ms_eval_log_lock = PTHREAD_MUTEX_INITIALIZER;

static void ms_eval_log_open_if_needed(void) {{
  if (ms_eval_log_opened) return;
  ms_eval_log_opened = 1;
  const char* log_path = getenv("LF_APP_LOG");
  if (log_path == NULL || log_path[0] == '\\0') return;
  ms_eval_log_fp = fopen(log_path, "a");
}}

static void ms_eval_append_json(const char* fmt, ...) {{
  ms_eval_log_open_if_needed();
  if (ms_eval_log_fp == NULL) return;
  pthread_mutex_lock(&ms_eval_log_lock);
  va_list args;
  va_start(args, fmt);
  vfprintf(ms_eval_log_fp, fmt, args);
  va_end(args);
  fputc('\\n', ms_eval_log_fp);
  fflush(ms_eval_log_fp);
  pthread_mutex_unlock(&ms_eval_log_lock);
}}

static void ms_eval_log_run_start(const char* mode,
                                  int reactions,
                                  int steps,
                                  int workload_us,
                                  int deadline_us,
                                  double load_factor,
                                  int seed) {{
  ms_eval_append_json(
      "{{\\\"type\\\":\\\"run_start\\\",\\\"ts_mono_ns\\\":%" PRId64
      ",\\\"experiment\\\":\\\"e3\\\",\\\"mode\\\":\\\"%s\\\","
      "\\\"reactions\\\":%d,\\\"steps\\\":%d,\\\"workload_us\\\":%d,"
      "\\\"deadline_us\\\":%d,\\\"load_factor\\\":%.3f,\\\"seed\\\":%d}}",
      ms_eval_now_mono_ns(),
      (mode != NULL ? mode : ""),
      reactions,
      steps,
      workload_us,
      deadline_us,
      load_factor,
      seed);
}}

static void ms_eval_log_reaction_start(int reaction_id,
                                       int64_t logical_time_ns,
                                       int64_t physical_time_ns) {{
  ms_eval_append_json(
      "{{\\\"type\\\":\\\"reaction_start\\\",\\\"ts_mono_ns\\\":%" PRId64
      ",\\\"logical_time_ns\\\":%" PRId64 ",\\\"reaction_id\\\":%d}}",
      physical_time_ns,
      logical_time_ns,
      reaction_id);
}}

static void ms_eval_log_reaction_end(int reaction_id,
                                     int64_t logical_time_ns,
                                     int64_t physical_time_ns,
                                     int64_t deadline_us,
                                     int missed_deadline) {{
  ms_eval_append_json(
      "{{\\\"type\\\":\\\"reaction_end\\\",\\\"ts_mono_ns\\\":%" PRId64
      ",\\\"logical_time_ns\\\":%" PRId64 ",\\\"reaction_id\\\":%d,"
      "\\\"deadline_us\\\":%" PRId64 ",\\\"missed_deadline\\\":%d}}",
      physical_time_ns,
      logical_time_ns,
      reaction_id,
      deadline_us,
      missed_deadline);
}}

static void ms_eval_busy_wait_us(int work_us) {{
  if (work_us <= 0) return;
  int64_t start = ms_eval_now_mono_ns();
  int64_t target = start + (int64_t)work_us * 1000LL;
  while (ms_eval_now_mono_ns() < target) {{
  }}
}}

static int ms_eval_steps = {steps};
static int ms_eval_seed = {seed};
static int ms_eval_hc_deadline_us = {hc_deadline_us};
static int ms_eval_lc_deadline_us = {lc_deadline_us};
static int ms_eval_hc_work_us = {hc_work_us};
static int ms_eval_lc_work_us = {lc_work_us};
static double ms_eval_load_factor = {load_factor};
static int ms_eval_log_reaction_start_enabled = -1;

static double ms_eval_get_env_double(const char* key, double fallback) {{
  const char* v = getenv(key);
  return v ? atof(v) : fallback;
}}

static int ms_eval_get_env_int(const char* key, int fallback) {{
  const char* v = getenv(key);
  return v ? atoi(v) : fallback;
}}

static int ms_eval_reaction_start_logging_enabled(void) {{
  if (ms_eval_log_reaction_start_enabled < 0) {{
    ms_eval_log_reaction_start_enabled = ms_eval_get_env_int("MS_EVAL_LOG_REACTION_START", 0);
  }}
  return ms_eval_log_reaction_start_enabled;
}}
=}}

reactor HCWorker(id:int = 0) {{
  timer t(0, {period_us} us);
  reaction(t) {{=
    const int reaction_id = self->id;
    int64_t logical = (int64_t)lf_time_logical();
    int64_t physical = (int64_t)lf_time_physical();
    if (ms_eval_reaction_start_logging_enabled()) {{
      ms_eval_log_reaction_start(reaction_id, logical, physical);
    }}
    ms_eval_busy_wait_us(ms_eval_hc_work_us);
    int64_t physical_end = (int64_t)lf_time_physical();
    int missed = (ms_eval_hc_deadline_us > 0 &&
                  physical_end > logical + (int64_t)ms_eval_hc_deadline_us * 1000LL);
    ms_eval_log_reaction_end(reaction_id, logical, physical_end, ms_eval_hc_deadline_us, missed);
  =}}
}}

reactor LCWorker(id:int = 0) {{
  timer t(0, {period_us} us);
  reaction(t) {{=
    const int reaction_id = self->id;
    int64_t logical = (int64_t)lf_time_logical();
    int64_t physical = (int64_t)lf_time_physical();
    if (ms_eval_reaction_start_logging_enabled()) {{
      ms_eval_log_reaction_start(reaction_id, logical, physical);
    }}
    ms_eval_busy_wait_us((int)(ms_eval_lc_work_us * ms_eval_load_factor));
    int64_t physical_end = (int64_t)lf_time_physical();
    int missed = (ms_eval_lc_deadline_us > 0 &&
                  physical_end > logical + (int64_t)ms_eval_lc_deadline_us * 1000LL);
    ms_eval_log_reaction_end(reaction_id, logical, physical_end, ms_eval_lc_deadline_us, missed);
  =}}
}}

reactor Stopper {{
  timer t(0, {period_us} us);
  state step:int = 0;
  reaction(t) {{=
    self->step++;
    if (self->step >= ms_eval_steps) {{
      lf_request_stop();
    }}
  =}}
}}

main reactor {{
  reaction(startup) {{=
    ms_eval_load_factor = ms_eval_get_env_double("MS_EVAL_LOAD_FACTOR", ms_eval_load_factor);
    const char* mode = getenv("MS_MODE");
    ms_eval_log_run_start(mode, {total_reactions}, ms_eval_steps,
                          ms_eval_hc_work_us, ms_eval_hc_deadline_us,
                          ms_eval_load_factor, ms_eval_seed);
  =}}

{instances_block}

  stopper = new Stopper();
}}
"""


def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument("--out", required=True)
    ap.add_argument("--hc", type=int, required=True)
    ap.add_argument("--lc", type=int, required=True)
    ap.add_argument("--hc-work-us", type=int, required=True)
    ap.add_argument("--lc-work-us", type=int, required=True)
    ap.add_argument("--hc-deadline-us", type=int, required=True)
    ap.add_argument("--lc-deadline-us", type=int, required=True)
    ap.add_argument("--period-us", type=int, default=1000)
    ap.add_argument("--steps", type=int, default=1000)
    ap.add_argument("--seed", type=int, default=1)
    ap.add_argument("--load-factor", type=float, default=1.0)
    ap.add_argument("--workers", type=int, default=4)
    args = ap.parse_args()

    instances = []
    total = args.hc + args.lc
    for rid in range(args.hc):
        instances.append(f"  hc_{rid} = new HCWorker(id={rid});")
    for off in range(args.lc):
        rid = args.hc + off
        instances.append(f"  lc_{off} = new LCWorker(id={rid});")

    out_path = Path(args.out)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    out_path.write_text(
        TEMPLATE.format(
            steps=args.steps,
            seed=args.seed,
            hc_deadline_us=args.hc_deadline_us,
            lc_deadline_us=args.lc_deadline_us,
            hc_work_us=args.hc_work_us,
            lc_work_us=args.lc_work_us,
            load_factor=args.load_factor,
            total_reactions=total,
            period_us=args.period_us,
            workers=args.workers,
            instances_block="\n".join(instances),
        )
    )


if __name__ == "__main__":
    main()
